// Verify /api/weather returns 400 when only lat is provided — schema catches missing lon
async function testWeatherPartialParams() {
  const res = await fetch('http://localhost:3001/api/weather?lat=45');
  assertEquals(res.status, 400);
  const body = await res.json();
  assertEquals(body.error, 'Validation failed');
  assert(body.details.some((d) => d.message.includes('lon')), 'Should flag missing lon');
}
